{
  "decision": "block_and_escalate",
  "rationale": "La telemetria EDR y la inteligencia de IPs indican una toma de cuenta probable, con un inicio de sesion anomalo desde una jurisdiccion sancionada y sin MFA. La informacion del calendario corporativo no desvirtua la evidencia canonica.",
  "claims": [
    {
      "text": "Inicio de sesion de j.torres desde una IP residencial en jurisdiccion sancionada, sin MFA satisfactorio y con huella de dispositivo no gestionada.",
      "source_id": "idp_login_event",
      "authority": 5
    },
    {
      "text": "El login anterior fue hace 40 min desde Madrid (viaje imposible).",
      "source_id": "idp_login_event",
      "authority": 5
    },
    {
      "text": "Patron coherente con toma de cuenta.",
      "source_id": "idp_login_event",
      "authority": 5
    },
    {
      "text": "La IP de origen pertenece a un rango asociado a infraestructura maliciosa usada en campanas de toma de cuenta.",
      "source_id": "geo_ip_intel",
      "authority": 4
    },
    {
      "text": "El dispositivo no coincide con ninguno gestionado del usuario.",
      "source_id": "geo_ip_intel",
      "authority": 4
    },
    {
      "text": "j.torres figura con estado 'De viaje' del 1 al 8 de julio y solicito acceso remoto desde su equipo personal.",
      "source_id": "hr_calendar_extract",
      "authority": 3
    }
  ],
  "memory_note": "Correlacionar actividad de inicio de sesion anomala con estado de viaje y solicitudes de acceso remoto."
}

